  border-top: 1px solid rgba(255,255,255,0.05);
  border-bottom: 1px solid rgba(255,255,255,0.05);
}

@keyframes glitch-bar-anim {
  0% { top: -10%; opacity: 0; }
  10% { opacity: 1; }
  90% { top: 110%; opacity: 1; }
  100% { top: 110%; opacity: 0; }
}

.rgb-text-glitch {
